 1	import { type FC, useMemo } from 'react';
 2	import { Controller, useFormContext } from 'react-hook-form';
 3	
 4	import { HelpIconPopover } from '@components/common/HelpIconPopover/HelpIconPopover';
 5	import Select from '@components/common/Select';
 6	import { FormGroup, Stack, StackItem } from '@patternfly/react-core';
 7	import { useForkliftTranslation } from '@utils/i18n';
 8	
 9	import { StorageMapFieldId, storageMapFieldLabels } from '../../constants';
10	import { useOffloadPlugins } from '../../hooks/useOffloadPlugins';
11	import { getPluginLabel } from '../../utils/labelHelpers';
12	
13	type OffloadPluginFieldProps = { fieldId: string };
14	
15	const OffloadPluginField: FC<OffloadPluginFieldProps> = ({ fieldId }) => {
16	  const { t } = useForkliftTranslation();
17	  const {
18	    control,
19	    formState: { isSubmitting },
20	  } = useFormContext();
21	  const { loading, offloadPlugins } = useOffloadPlugins();
22	
23	  const options = useMemo(
24	    () =>
25	      offloadPlugins.map((plugin) => ({
26	        label: getPluginLabel(plugin),
27	        value: plugin,
28	      })),
29	    [offloadPlugins],
30	  );
31	
32	  return (
33	    <FormGroup
34	      fieldId={fieldId}
35	      label={storageMapFieldLabels[StorageMapFieldId.OffloadPlugin]}
36	      labelHelp={
37	        <HelpIconPopover>
38	          <Stack hasGutter>
39	            <StackItem>
40	              {t(
41	                'Enables hardware-assisted copying by instructing the vSphere ESXi host to transfer data directly on the storage backend using technologies like XCOPY and VAAI.',
42	              )}
43	            </StackItem>
44	            <StackItem>
45	              {t(
46	                'This significantly speeds up the migration process and frees up network and host resources by avoiding the need to pull data through the source host.',
47	              )}
48	            </StackItem>
49	          </Stack>
50	        </HelpIconPopover>
51	      }
52	    >
53	      <Controller
54	        name={fieldId}
55	        control={control}
56	        render={({ field }) => (
57	          <Select
58	            ref={field.ref}
59	            id={fieldId}
60	            isDisabled={isSubmitting || loading}
61	            value={field.value}
62	            options={options}
63	            onSelect={(_event, value) => {
64	              field.onChange(value);
65	            }}
66	            placeholder={t('Select offload plugin')}
67	          />
68	        )}
69	      />
70	    </FormGroup>
71	  );
72	};
73	
74	export default OffloadPluginField;

