 1	import { describe, expect, it, jest } from '@jest/globals';
 2	import { mockI18n } from '@test-utils/mockI18n';
 3	import { renderWithForm } from '@test-utils/renderWithForm';
 4	import { screen } from '@testing-library/react';
 5	import userEvent from '@testing-library/user-event';
 6	
 7	import { useOffloadPlugins } from '../../../hooks/useOffloadPlugins';
 8	import OffloadPluginField from '../OffloadPluginField';
 9	
10	jest.mock('../../../hooks/useOffloadPlugins');
11	mockI18n();
12	
13	const mockUseOffloadPlugins = useOffloadPlugins as jest.MockedFunction<typeof useOffloadPlugins>;
14	
15	describe('OffloadPluginField', () => {
16	  beforeEach(() => {
17	    jest.clearAllMocks();
18	  });
19	
20	  it('disables the select when loading', () => {
21	    mockUseOffloadPlugins.mockReturnValue({
22	      error: null,
23	      loading: true,
24	      offloadPlugins: [],
25	    });
26	
27	    renderWithForm(<OffloadPluginField fieldId="test-field" />);
28	
29	    expect(screen.getByRole('button', { name: 'Select menu toggle' })).toBeDisabled();
30	  });
31	
32	  it('allows user to open dropdown and see available plugins', async () => {
33	    const user = userEvent.setup();
34	    mockUseOffloadPlugins.mockReturnValue({
35	      error: null,
36	      loading: false,
37	      offloadPlugins: ['vsphereXcopyConfig', 'newPlugin'],
38	    });
39	
40	    renderWithForm(<OffloadPluginField fieldId="test-field" />);
41	
42	    const select = screen.getByRole('button', { name: 'Select menu toggle' });
43	    expect(select).toBeEnabled();
44	    expect(select).toHaveTextContent('Select offload plugin');
45	
46	    await user.click(select);
47	    expect(screen.getByRole('listbox')).toBeInTheDocument();
48	  });
49	
50	  it('shows fallback plugins when there is an error', async () => {
51	    const user = userEvent.setup();
52	    mockUseOffloadPlugins.mockReturnValue({
53	      error: new Error('API Error'),
54	      loading: false,
55	      offloadPlugins: ['vsphereXcopyConfig'],
56	    });
57	
58	    renderWithForm(<OffloadPluginField fieldId="test-field" />);
59	
60	    const select = screen.getByRole('button', { name: 'Select menu toggle' });
61	    expect(select).toBeEnabled();
62	
63	    await user.click(select);
64	    expect(screen.getByRole('listbox')).toBeInTheDocument();
65	  });
66	});

